mapper.select:
SELECT id FROM trainer_pricing
WHERE trainer_id = #{trainerId}
  AND session_count= #{sessionCount}
LIMIT 1

mapper.update:
UPDATE MEMBERSHIP_PT
SET status = #{status}
WHERE id = #{id}

UPDATE MEMBERSHIP_PT
SET lesson_count = lesson_count + #{sessionCount}
WHERE id = #{id}

UPDATE MEMBERSHIP_PT
SET next_session = #{nextSession},
    last_session = #{lastSession}
WHERE id = #{id}
